"use client";

import { motion } from "framer-motion";
import Image from "next/image";

const items = [
  { id: 1, src: "/image/photo/porto-1.jpg", title: "Prom Night '24", span: "md:col-span-2 md:row-span-2" },
  { id: 2, src: "/image/photo/porto-2.jpg", title: "Corporate Gathering", span: "col-span-1 row-span-1" },
  { id: 3, src: "/image/photo/porto-3.jpg", title: "Private Party", span: "col-span-1 row-span-1" },
  { id: 4, src: "/image/photo/porto-4.jpg", title: "Wedding Anniversary", span: "col-span-1 row-span-1" },
  { id: 5, src: "/image/photo/porto-5.jpg", title: "Launch Event", span: "col-span-1 row-span-1" },
  { id: 6, src: "/image/photo/porto-6.jpg", title: "Gala Dinner", span: "md:col-span-2 row-span-1" },
];

export default function Gallery() {
  return (
    <section id="portfolio" className="py-24 bg-[#f8fafc]">
      <div className="container mx-auto px-6">
        <div className="flex flex-col md:flex-row justify-between items-end mb-16">
          <div className="mb-6 md:mb-0">
            <motion.p
              initial={{ opacity: 0, x: -20 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              className="text-blue-600 uppercase text-sm font-bold tracking-widest mb-4"
            >
              Our Portfolio
            </motion.p>
            <motion.h2
              initial={{ opacity: 0, x: -20 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              transition={{ delay: 0.1 }}
              className="text-4xl md:text-5xl font-extrabold tracking-tight text-[#0f172a] mb-6"
            >
              Moments we've <br /> brought to life
            </motion.h2>
          </div>
          
          <motion.button
            initial={{ opacity: 0 }}
            whileInView={{ opacity: 1 }}
            viewport={{ once: true }}
            className="text-[#0f172a] font-bold border-b-2 border-pink-500 pb-1 hover:text-pink-600 transition-colors uppercase tracking-widest text-sm"
          >
            View Full Gallery
          </motion.button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 auto-rows-[250px]">
          {items.map((item, index) => (
            <motion.div
              key={item.id}
              initial={{ opacity: 0, scale: 0.95 }}
              whileInView={{ opacity: 1, scale: 1 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.1, duration: 0.5 }}
              whileHover={{ scale: 0.98 }}
              className={`relative overflow-hidden rounded-3xl group cursor-pointer shadow-sm hover:shadow-xl transition-all ${item.span}`}
            >
              <Image
                src={item.src}
                alt={item.title}
                fill
                className="object-cover transition-transform duration-700 group-hover:scale-110"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-[#0f172a]/80 via-[#0f172a]/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
              <div className="absolute bottom-6 left-6 translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-300">
                <span className="bg-white/20 backdrop-blur-md text-white px-3 py-1 rounded-full text-xs font-bold uppercase tracking-widest mb-3 inline-block">Event</span>
                <h3 className="text-white text-2xl font-bold">{item.title}</h3>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}
