"use client";

import { motion } from "framer-motion";
import { PartyPopper, Music, Briefcase, Sparkles } from "lucide-react";

const services = [
  {
    title: "Parties",
    description: "Fun, vibrant, and unforgettable private parties tailored to your unique style.",
    icon: PartyPopper,
    color: "from-pink-400 to-pink-600",
    bg: "bg-pink-50",
    text: "text-pink-600"
  },
  {
    title: "Prom Nights",
    description: "Magical prom experiences with spectacular themes, great music, and memories that last.",
    icon: Music,
    color: "from-purple-400 to-purple-600",
    bg: "bg-purple-50",
    text: "text-purple-600"
  },
  {
    title: "Company Gatherings",
    description: "Professional yet engaging corporate events to boost team spirit and celebrate milestones.",
    icon: Briefcase,
    color: "from-blue-400 to-blue-600",
    bg: "bg-blue-50",
    text: "text-blue-600"
  },
  {
    title: "Custom Concepts",
    description: "Got a wild idea? We turn your creative imagination into a beautifully executed reality.",
    icon: Sparkles,
    color: "from-orange-400 to-orange-600",
    bg: "bg-orange-50",
    text: "text-orange-600"
  },
];

export default function Services() {
  return (
    <section id="services" className="py-24 bg-white relative overflow-hidden">
      <div className="container mx-auto px-6 relative z-10">
        <div className="text-center mb-16">
          <motion.p
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            className="text-pink-600 uppercase text-sm font-bold tracking-widest mb-4"
          >
            Our Expertise
          </motion.p>
          <motion.h2
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ delay: 0.1 }}
            className="text-4xl md:text-5xl font-extrabold tracking-tight text-[#0f172a] mb-6"
          >
            What we do best
          </motion.h2>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {services.map((service, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.1, duration: 0.5 }}
              whileHover={{ y: -10 }}
              className="bg-white p-8 rounded-3xl shadow-lg border border-slate-100 hover:shadow-2xl hover:shadow-slate-200 transition-all group"
            >
              <div className={`w-16 h-16 rounded-2xl ${service.bg} flex items-center justify-center mb-6 text-white group-hover:scale-110 transition-transform duration-300 bg-gradient-to-br ${service.color}`}>
                <service.icon size={32} strokeWidth={2} />
              </div>
              <h3 className="text-2xl font-bold text-[#0f172a] mb-4">
                {service.title}
              </h3>
              <p className="text-slate-600 font-medium leading-relaxed">
                {service.description}
              </p>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}
